// Verify Meta's GET challenge.
// Meta sends: ?hub.mode=subscribe&hub.verify_token=X&hub.challenge=Y
// We respond with Y as plain text 200 only if X matches our shared secret.
// NOTE: n8n's task-runner sandbox blocks `process` — use `$env.VAR` instead.
const query = $input.first().json.query || {};
const mode = query['hub.mode'];
const token = query['hub.verify_token'];
const challenge = query['hub.challenge'];
const expectedToken = $env.META_WEBHOOK_VERIFY_TOKEN || '';

if (mode === 'subscribe' && token && expectedToken && token === expectedToken) {
  return [{ json: { ok: true, body: String(challenge || '') } }];
}

return [{ json: { ok: false, body: 'Forbidden', status: 403 } }];

// Parse Meta delivery status payload and emit one item per status event.
// Payload shape:
//   { object: 'whatsapp_business_account',
//     entry: [{ id, changes: [{ value: { statuses: [{ id (wamid), status, timestamp, recipient_id, errors? }], messages: [...] }, field: 'messages' }] }] }
//
// Statuses: sent, delivered, read, failed.
// We log each one — this is the visibility we previously lacked when Meta
// silently throttled our sends (May 17-20 2026 incident).
const body = $input.first().json.body || {};
const out = [];

for (const entry of body.entry || []) {
  for (const change of entry.changes || []) {
    if (change.field !== 'messages') continue;
    const value = change.value || {};
    for (const status of value.statuses || []) {
      out.push({
        json: {
          wamid: status.id,
          status: status.status,
          timestamp: status.timestamp,
          recipient: status.recipient_id,
          conversation_id: status.conversation?.id,
          category: status.conversation?.origin?.type,
          pricing_category: status.pricing?.category,
          billable: status.pricing?.billable,
          errors: status.errors,
        },
      });
    }
    // Also log inbound messages (replies from recipients) for completeness.
    for (const msg of value.messages || []) {
      out.push({
        json: {
          inbound: true,
          from: msg.from,
          type: msg.type,
          text: msg.text?.body,
          timestamp: msg.timestamp,
        },
      });
    }
  }
}

return out.length > 0 ? out : [{ json: { note: 'no statuses or messages in payload', body } }];
